package com.enterprise.oauth.service;

import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.security.SecureRandom;
import java.util.Base64;

@Service
public class StateService {

    private static final SecureRandom secureRandom = new SecureRandom();
    private static final String STATE_SESSION_KEY = "oauth2_state";

    /**
     * Generates a cryptographically secure random state parameter
     * and stores it in the user's session for later validation.
     * This prevents CSRF attacks on the OAuth callback endpoint.
     */
    public String generateAndStoreState(HttpSession session) {
        byte[] randomBytes = new byte[32];
        secureRandom.nextBytes(randomBytes);
        String state = Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
        session.setAttribute(STATE_SESSION_KEY, state);
        return state;
    }

    /**
     * Validates that the state returned by the authorization server
     * matches the one we stored in the session.
     */
    public boolean validateState(HttpSession session, String returnedState) {
        String storedState = (String) session.getAttribute(STATE_SESSION_KEY);
        session.removeAttribute(STATE_SESSION_KEY);
        return storedState != null && storedState.equals(returnedState);
    }
}

