package com.enterprise.oauth.service;

import com.enterprise.oauth.config.OAuthConfig;
import org.springframework.stereotype.Service;
import org.springframework.web.util.UriComponentsBuilder;

@Service
public class AuthorizationUrlBuilder {

    private final OAuthConfig oAuthConfig;

    public AuthorizationUrlBuilder(OAuthConfig oAuthConfig) {
        this.oAuthConfig = oAuthConfig;
    }

    /**
     * Builds the OAuth 2.0 authorization URL with all required parameters
     * including the state parameter for CSRF protection.
     */
    public String buildAuthorizationUrl(String state) {
        return UriComponentsBuilder
                .fromUriString(oAuthConfig.getAuthorizationUri())
                .queryParam("response_type", "code")
                .queryParam("client_id", oAuthConfig.getClientId())
                .queryParam("redirect_uri", oAuthConfig.getRedirectUri())
                .queryParam("scope", oAuthConfig.getScope())
                .queryParam("state", state)
                .build()
                .toUriString();
    }
}

