package com.enterprise.oauth.service;

import com.enterprise.oauth.config.OAuthConfig;
import com.enterprise.oauth.model.TokenResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

@Service
public class TokenExchangeService {

    private static final Logger logger = LoggerFactory.getLogger(TokenExchangeService.class);

    private final OAuthConfig oAuthConfig;
    private final RestTemplate restTemplate;

    public TokenExchangeService(OAuthConfig oAuthConfig) {
        this.oAuthConfig = oAuthConfig;
        this.restTemplate = new RestTemplate();
    }

    public TokenResponse exchangeCodeForToken(String authorizationCode) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "authorization_code");
        body.add("code", authorizationCode);
        body.add("redirect_uri", oAuthConfig.getRedirectUri());
        body.add("client_id", oAuthConfig.getClientId());
        body.add("client_secret", oAuthConfig.getClientSecret());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        logger.info("Exchanging authorization code for access token");

        ResponseEntity<TokenResponse> response = restTemplate.exchange(
                oAuthConfig.getTokenUri(),
                HttpMethod.POST,
                request,
                TokenResponse.class
        );

        logger.info("Token exchange successful");
        return response.getBody();
    }
}

