package com.enterprise.oauth.controller;

import com.enterprise.oauth.model.TokenResponse;
import com.enterprise.oauth.service.AuthorizationUrlBuilder;
import com.enterprise.oauth.service.StateService;
import com.enterprise.oauth.service.TokenExchangeService;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

@Controller
public class OAuthController {

    private static final Logger logger = LoggerFactory.getLogger(OAuthController.class);

    private final AuthorizationUrlBuilder authorizationUrlBuilder;
    private final TokenExchangeService tokenExchangeService;
    private final StateService stateService;

    public OAuthController(AuthorizationUrlBuilder authorizationUrlBuilder,
                           TokenExchangeService tokenExchangeService,
                           StateService stateService) {
        this.authorizationUrlBuilder = authorizationUrlBuilder;
        this.tokenExchangeService = tokenExchangeService;
        this.stateService = stateService;
    }

    @GetMapping("/")
    public String home() {
        return "home";
    }

    /**
     * Initiates the OAuth 2.0 authorization code flow by redirecting
     * the user to the authorization server.
     */
    @GetMapping("/oauth/authorize")
    public String authorize(HttpSession session) {
        // Generate a secure random state to prevent CSRF attacks
        String state = stateService.generateAndStoreState(session);
        String authorizationUrl = authorizationUrlBuilder.buildAuthorizationUrl(state);

        logger.info("Redirecting user to authorization server");
        return "redirect:" + authorizationUrl;
    }

    /**
     * Handles the OAuth 2.0 callback from the authorization server.
     * Validates the state parameter and exchanges the authorization code for tokens.
     */
    @GetMapping("/oauth/callback")
    public String callback(
            @RequestParam(value = "code", required = false) String code,
            @RequestParam(value = "state", required = false) String state,
            @RequestParam(value = "error", required = false) String error,
            @RequestParam(value = "error_description", required = false) String errorDescription,
            HttpSession session,
            Model model) {

        // Handle authorization errors
        if (error != null) {
            logger.error("Authorization error: {} - {}", error, errorDescription);
            model.addAttribute("error", error);
            model.addAttribute("errorDescription", errorDescription);
            return "error";
        }

        // Validate the state parameter to prevent CSRF attacks
        if (!stateService.validateState(session, state)) {
            logger.error("State parameter mismatch - possible CSRF attack");
            model.addAttribute("error", "invalid_state");
            model.addAttribute("errorDescription",
                    "State parameter validation failed. This may indicate a CSRF attack.");
            return "error";
        }

        // Exchange authorization code for access token
        try {
            TokenResponse tokenResponse = tokenExchangeService.exchangeCodeForToken(code);
            model.addAttribute("tokenType", tokenResponse.getTokenType());
            model.addAttribute("expiresIn", tokenResponse.getExpiresIn());
            model.addAttribute("scope", tokenResponse.getScope());
            model.addAttribute("authenticated", true);

            // Store token in session (in production, use a more secure token store)
            session.setAttribute("access_token", tokenResponse.getAccessToken());

            logger.info("User authenticated successfully");
            return "success";
        } catch (Exception e) {
            logger.error("Token exchange failed", e);
            model.addAttribute("error", "token_exchange_failed");
            model.addAttribute("errorDescription", "Failed to exchange authorization code for token.");
            return "error";
        }
    }

    @GetMapping("/logout")
    public String logout(HttpSession session) {
        session.invalidate();
        return "redirect:/";
    }
}